#include <bits/stdc++.h>
using namespace std;
int a[105];
int main(){
    int n;
    cin>>n;
    for(int i=1;i<=n;i++){
        cin>>a[i];
    }
    int x,y,m;
    cin>>m;
    for(int i=0;i<m;i++){
        cin>>x>>y;
        sort(a+x,a+y+1);
    }
    for(int i=1;i<=n;i++){
		cout<<a[i]<<" ";
    }
    return 0;
}
